CREATE MATERIALIZED VIEW public.attempt_responses_mv AS
 SELECT DISTINCT ON (r.id) r.id AS response_id,
    r.chat_id,
    rqc.question_id,
    roc.option_id,
    r.created_at
   FROM ((public.attempt_responses_entry r
     LEFT JOIN public.attempt_responses_questions_connection rqc ON (((rqc.responses_id = r.id) AND (rqc.active = true))))
     LEFT JOIN public.attempt_responses_options_connection roc ON (((roc.responses_id = r.id) AND (roc.active = true))))
  WHERE (r.active = true)
  ORDER BY r.id, r.created_at DESC
  WITH NO DATA;


